import React, { useState } from "react";

const ImageGenerator = () => {
  const [prompt, setPrompt] = useState("");
  const [image, setImage] = useState("");
  const [loading, setLoading] = useState(false);

  const handleGenerate = () => {
    if (!prompt) return;
    setLoading(true);
    const imageUrl = `https://image.pollinations.ai/prompt/${encodeURIComponent(prompt)}?nologo=true`;
    setImage(""); // reset first
    setTimeout(() => {
      setImage(imageUrl);
      setLoading(false);
    }, 1500);
  };

  return (
    <div className="p-6">
      <h1 className="text-2xl font-bold mb-4">AI Image Generator</h1>

      <input
        type="text"
        placeholder="Enter prompt..."
        value={prompt}
        onChange={(e) => setPrompt(e.target.value)}
        className="w-full p-3 border rounded-lg mb-4"
      />

      <button
        onClick={handleGenerate}
        className="bg-blue-500 text-white px-6 py-2 rounded-lg"
      >
        Generate Image
      </button>

      {loading && <p className="mt-4">Generating...</p>}

      {image && (
        <img src={image} alt="AI result" className="mt-4 rounded-lg" onError={(e) => {e.target.src = "https://via.placeholder.com/400?text=Image+Not+Available";}} />
      )}
    </div>
  );
};

export default ImageGenerator;
